50	///
51	/// One [`VulnFinding`] per `(site, sink)` deviation, merging all guards the
52	/// site is missing. Sorted by confidence descending (strongest norm first).
53	pub fn mine_missing_guards(graph: &CodeGraph, config: &MineConfig) -> Vec<VulnFinding> {
54	    // Merge key: a single caller→sink site may be missing several guards; we
55	    // emit one finding listing them all.
56	    let mut merged: HashMap<(NodeId, NodeId), Deviation> = HashMap::new();
57	
58	    for sink in graph.nodes_by_kind(NodeKind::Function) {
59	        let sink_id = &sink.id;
60	
61	        // Distinct callers of this sink, with the earliest call-site line each
62	        // (a guard must precede the *first* reach to count).
63	        let mut caller_sink_line: HashMap<NodeId, u32> = HashMap::new();
64	        for (src, edge) in graph.get_edges_to(sink_id) {
65	            if !is_call(&edge.kind) || src == sink_id {
66	                continue;
67	            }
68	            let line = edge.source_span.start_line;
69	            caller_sink_line
70	                .entry(src.clone())
71	                .and_modify(|l| *l = (*l).min(line))
72	                .or_insert(line);
73	        }
74	        let total = caller_sink_line.len();
75	        if total < config.min_callers {
76	            continue;
77	        }
78	
79	        // guard candidate -> set of callers that invoke it before the sink.
80	        let mut guard_callers: HashMap<NodeId, HashSet<NodeId>> = HashMap::new();
81	        for (caller, &sink_line) in &caller_sink_line {
82	            for (callee, edge) in graph.get_edges_from(caller) {
83	                if !is_call(&edge.kind) || callee == sink_id || callee == caller {
84	                    continue;
85	                }
86	                if edge.source_span.start_line < sink_line {
87	                    guard_callers
88	                        .entry(callee.clone())
89	                        .or_default()
90	                        .insert(caller.clone());
91	                }
92	            }
93	        }
94	
95	        for (guard, callers_with) in &guard_callers {
96	            let support = callers_with.len();
97	            let freq = support as f64 / total as f64;
98	            // A norm: shared by most callers, but not all (else no deviant).
99	            if support < config.min_support as usize || freq < config.threshold || support >= total
100	            {
101	                continue;
102	            }
103	            // Every caller missing this guard is a deviation.
104	            for caller in caller_sink_line.keys() {
105	                if callers_with.contains(caller) {
106	                    continue;
107	                }
108	                let dev = merged
109	                    .entry((caller.clone(), sink_id.clone()))
110	                    .or_insert_with(|| Deviation {
111	                        total: total as u32,
112	                        ..Deviation::default()
113	                    });
114	                dev.expected.push(guard.clone());
115	                dev.support = dev.support.max(support as u32);
116	                dev.confidence = dev.confidence.max(freq);
117	            }
118	        }
119	    }
120	
121	    let mut findings: Vec<VulnFinding> = merged
122	        .into_iter()
123	        .map(|((site, sink), dev)| build_finding(graph, site, sink, dev))
124	        .collect();
125	    findings.sort_by(|a, b| {
126	        b.confidence
127	            .partial_cmp(&a.confidence)
128	            .unwrap_or(std::cmp::Ordering::Equal)
129	            .then_with(|| a.site.0.cmp(&b.site.0))
130	            .then_with(|| a.sink.0.cmp(&b.sink.0))
131	    });
132	    findings
133	}
