75:     /// Verify every proposal. Sinks are checked first (guards are verified
76:     /// relative to verified sinks). Returns one [`VerifiedRole`] per proposal,
77:     /// with `verified` set; callers keep only the verified ones.
78:     pub fn verify(&self, proposals: &[RoleProposal]) -> Vec<VerifiedRole> {
79:         // Pass 1: which proposed sinks survive the in-degree check.
80:         let verified_sinks: Vec<NodeId> = proposals
81:             .iter()
82:             .filter(|p| p.role == PredicateRole::Sink)
83:             .filter(|p| self.distinct_callers(&p.node) >= self.min_callers)
84:             .map(|p| p.node.clone())
85:             .collect();
86: 
87:         proposals
88:             .iter()
89:             .map(|p| {
90:                 let verified = match p.role {
91:                     PredicateRole::Sink => verified_sinks.contains(&p.node),
92:                     PredicateRole::Guard => verified_sinks
93:                         .iter()
94:                         .any(|s| self.precedes_in_some_caller(&p.node, s)),
95:                     // A sanitizer must actually be invoked somewhere.
96:                     PredicateRole::Sanitizer => self.distinct_callers(&p.node) >= 1,
97:                     // A source must actually flow somewhere (have callees).
98:                     PredicateRole::Source => !self.callees(&p.node).is_empty(),
99:                 };
100:                 VerifiedRole {
101:                     node: p.node.clone(),
102:                     role: p.role,
103:                     confidence: p.confidence,
104:                     origin: InferenceOrigin::Llm,
105:                     rationale: p.rationale.clone(),
106:                     verified,
107:                 }
108:             })
109:             .collect()
110:     }
111: 
112:     /// Distinct caller functions of `node` via resolved `Calls` edges.
113:     fn distinct_callers(&self, node: &NodeId) -> usize {
114:         let mut callers: HashSet<&NodeId> = HashSet::new();
115:         for (src, edge) in self.graph.get_edges_to(node) {
116:             if matches!(edge.kind, EdgeKind::Calls) && src != node {
117:                 callers.insert(src);
118:             }
119:         }
120:         callers.len()
121:     }
122: 
123:     fn callees(&self, node: &NodeId) -> Vec<NodeId> {
124:         self.graph
125:             .get_edges_from(node)
126:             .into_iter()
127:             .filter(|(_, e)| matches!(e.kind, EdgeKind::Calls))
128:             .map(|(t, _)| t.clone())
129:             .collect()
130:     }
131: 
132:     /// True if some caller calls `guard` strictly before its call to `sink`.
133:     fn precedes_in_some_caller(&self, guard: &NodeId, sink: &NodeId) -> bool {
134:         // Callers of the sink, with the earliest sink call-site line.
135:         for (caller, sink_edge) in self.graph.get_edges_to(sink) {
136:             if !matches!(sink_edge.kind, EdgeKind::Calls) || caller == sink {
137:                 continue;
138:             }
139:             let sink_line = sink_edge.source_span.start_line;
140:             for (callee, edge) in self.graph.get_edges_from(caller) {
141:                 if matches!(edge.kind, EdgeKind::Calls)
142:                     && callee == guard
143:                     && edge.source_span.start_line < sink_line
144:                 {
145:                     return true;
146:                 }
147:             }
148:         }
149:         false
150:     }
151: }
