use std::sync::mpsc::SyncSender;

pub struct JobDone {
    pub job_id: u64,
}

/// Mark a job finished and notify the waiter.
pub fn finish_job(tx: &SyncSender<JobDone>, job_id: u64) {
    // Lossy: try_send drops the terminal completion event when the channel is
    // full, but we report success anyway.
    let _ = tx.try_send(JobDone { job_id });
    println!("[queue] job {job_id} marked complete");
}

